-- Recursion & Backtracking
('CODING','Generate all permutations of an array.','','Backtracking: swap current position with each position i>=current. Recurse, then swap back.','permute(arr, start): if start==end add copy. For i in start..end: swap(start,i), recurse(start+1), swap back.','Medium','Backtracking','Any',NULL,1),
('CODING','Generate all subsets (power set) of an array.','','Backtracking or bitmask. For n elements there are 2^n subsets.','Recursive: at each index, choose include or exclude. Or bitmask: 0 to 2^n-1, bit i = include arr[i].','Medium','Backtracking','Any',NULL,1),
('CODING','N-Queens: place N queens on NxN board so no two attack each other.','','Backtracking row by row. Track cols, diag1, diag2 sets to check conflicts.','Place queen in each valid column of current row. Valid if col, (row-col), (row+col) not in used sets.','Hard','Backtracking','Any',NULL,1),
('CODING','Sudoku solver.','','Backtracking: find empty cell, try 1-9, check validity, recurse. Backtrack if no valid digit.','Find empty cell. Try digits 1-9: if safe(row,col,digit) place it, recurse, if fails reset and try next.','Hard','Backtracking','Google','Any',1),
('CODING','Word search: find if word exists in a 2D grid following adjacent cells.','','DFS/backtracking from each cell matching word[0]. Mark visited, explore 4 directions.','dfs(i,j,k): if k==len return true. Check bounds and grid[i][j]==word[k], mark visited, explore 4 dirs.','Medium','Backtracking','Any',NULL,1),
('CODING','Combination sum: find all combinations that sum to target.','','Backtracking. At each step decide to include current element (can reuse) or move to next.','backtrack(start, target, current): if target==0 add current. For i in start..n: if candidates[i]<=target recurse.','Medium','Backtracking','Amazon','Any',1),

-- Bit Manipulation
('CODING','Count number of 1 bits (Hamming weight) in an integer.','','n & (n-1) clears the lowest set bit. Count iterations until n=0.','Loop: count += n&1; n>>=1. Or: while n: count+=1; n&=(n-1). The latter is faster for sparse bits.','Easy','Bit Manipulation','Any',NULL,1),
('CODING','Find the single number in array where every other appears twice.','','XOR all elements. Pairs cancel out (a XOR a = 0), single number remains.','result = 0. For each num: result ^= num. Return result.','Easy','Bit Manipulation','Any',NULL,1),
('CODING','Reverse bits of a 32-bit unsigned integer.','','Shift result left and add rightmost bit of input, shift input right. 32 iterations.','result=0. For 32 iterations: result=(result<<1)|(n&1); n>>=1. Return result.','Easy','Bit Manipulation','Any',NULL,1),
('CODING','Power of two: check if a number is a power of 2.','','A power of 2 has exactly one set bit. n & (n-1) == 0 (and n > 0).','return n > 0 && (n & (n-1)) == 0.','Easy','Bit Manipulation','Any',NULL,1),

-- Two Pointers
('CODING','Three sum: find all unique triplets that sum to zero.','','Sort array. For each element, use two pointers for remaining pair. Skip duplicates.','Sort. For i, fix arr[i], two pointers l=i+1, r=n-1. Move inward on sum comparison, skip dupes.','Medium','Two Pointers','Amazon','Any',1),
('CODING','Container with most water: find two lines that hold the most water.','','Two pointers from ends. Move the shorter line inward. Track max area.','l=0, r=n-1. area=min(h[l],h[r])*(r-l). Move pointer with smaller height. Track max area.','Medium','Two Pointers','Any',NULL,1),
('CODING','Partition labels: partition string so each letter appears in at most one part.','','Track last occurrence of each char. Greedily extend partition until current pos reaches end of all chars in partition.','last[c]=last index of c. Iterate: end=max(end,last[s[i]]). If i==end: record partition size, reset.','Medium','Two Pointers','Any',NULL,1),

