INSERT INTO questions (question_type, question_text, options, answer, explanation, difficulty, topic, company_tag, language, active) VALUES
('CODING','Implement binary search on a sorted array.','','Return mid if found. If target < mid, search left half. If target > mid, search right half. O(logn).','lo=0, hi=n-1. While lo<=hi: mid=(lo+hi)/2. If arr[mid]==target return mid. If target<arr[mid]: hi=mid-1. Else lo=mid+1. Return -1.','Easy','Searching','Any',NULL,1),
('CODING','Count the number of occurrences of a character in a string.','','Iterate string, count matches. Or use collections.Counter. O(n).','Simple loop: count=0; for c in s: if c==char: count++. Return count.','Easy','Strings','Any',NULL,1),
('CODING','Find the GCD of two numbers using Euclidean algorithm.','','gcd(a,b) = gcd(b, a%b). Base case: gcd(a,0)=a.','Recursive: if b==0 return a. return gcd(b, a%b). Iterative: while b: a,b=b,a%b. return a.','Easy','Math','Any',NULL,1),
('CODING','Check if a number is prime.','','Trial division up to sqrt(n). Handle n<2, n=2, even numbers.','if n<2 return false. if n==2 return true. if n%2==0 return false. for i in 3..sqrt(n) step 2: if n%i==0 return false. return true.','Easy','Math','Any',NULL,1),
('CODING','Find all prime factors of a number.','','Divide by 2, then odd numbers up to sqrt(n). If remaining n > 1, it is a prime factor.','while n%2==0: add 2, n/=2. for i=3 to sqrt(n) step 2: while n%i==0: add i, n/=i. if n>1: add n.','Easy','Math','Any',NULL,1),
('CODING','Convert decimal to binary.','','Divide by 2 repeatedly, collect remainders in reverse.','while n>0: bits.prepend(n%2); n//=2. Or use bin(n) built-in.','Easy','Bit Manipulation','Any',NULL,1),
('CODING','Find the sum of digits of a number.','','Extract last digit by n%10, add to sum, divide n by 10 until n=0.','sum=0; while n>0: sum+=n%10; n//=10. return sum.','Easy','Math','Any',NULL,1),
('CODING','Reverse a string without using built-in reverse.','','Two pointers from ends, swap. Or recursion. Or stack.','i=0, j=len-1. While i<j: swap(s[i],s[j]); i++; j--','Easy','Strings','Any',NULL,1),
('CODING','Check if a number is Armstrong (narcissistic) number.','','Sum of each digit raised to power (number of digits) == number.','digits=str(n); n_dig=len(digits); return sum(int(d)**n_dig for d in digits)==n.','Easy','Math','Any',NULL,1),
('CODING','Find the factorial of a number (iterative and recursive).','','Iterative: product from 1 to n. Recursive: n*factorial(n-1), base case 0!=1.','Recursive: if n<=1 return 1. return n*factorial(n-1). Iterative: result=1; for i in 2..n: result*=i.','Easy','Recursion','Any',NULL,1),
('CODING','Remove duplicates from a sorted array in-place.','','Two pointer: write pointer for unique elements. O(n) time, O(1) space.','j=0. For i in 1..n-1: if arr[i]!=arr[j]: j++; arr[j]=arr[i]. Return j+1.','Easy','Arrays','Any',NULL,1),
('CODING','Implement stack using array.','','Array with top pointer. Push: check overflow, add and increment top. Pop: check underflow, return and decrement.','top=-1, arr[MAX]. push: if top==MAX-1 overflow. arr[++top]=val. pop: if top==-1 underflow. return arr[top--].','Easy','Stacks','Any',NULL,1),
('CODING','Implement queue using array (circular queue).','','front and rear pointers, modulo for wrap-around. Track size for full/empty distinction.','front=rear=0, size=0. Enqueue: if size==MAX overflow. arr[rear]=val; rear=(rear+1)%MAX; size++. Dequeue: val=arr[front]; front=(front+1)%MAX; size--.','Medium','Queues','Any',NULL,1),
('CODING','Find the maximum element in a stack in O(1).','','Use auxiliary max-stack or store (value, current_max) pairs.','Push pair (val, max(val, peek().max)). Pop returns top pair. max() returns top.max.','Easy','Stacks','Any',NULL,1),
('CODING','Implement a binary search tree (insert, search, delete).','','Insert: compare with root, go left/right recursively. Search: same. Delete: 3 cases (no child, one child, two children - replace with in-order successor).','Delete with 2 children: find in-order successor (min in right subtree), copy its value to current node, delete successor from right subtree.','Medium','Trees','Any',NULL,1),
('CODING','Find the in-order, pre-order, and post-order traversal of a BST.','','In-order: left, root, right (gives sorted order in BST). Pre-order: root, left, right. Post-order: left, right, root.','Recursive implementations: inorder(left), visit(node), inorder(right). Use stack for iterative versions.','Easy','Trees','Any',NULL,1),
('CODING','Count the number of nodes in a complete binary tree.','','O(logn * logn): at each level, check if right subtree height equals expected. If so left is perfect.','height(root)=O(logn). If height(root.right)==h-1, left subtree is perfect (2^(h-1) nodes). If height(root.right)==h-2, right subtree is perfect (2^(h-2) nodes). Recurse appropriately.','Hard','Trees','Any',NULL,1),
('CODING','Implement insertion sort.','','Pick each element, find its correct position in sorted left portion by shifting.','For i=1 to n-1: key=arr[i]; j=i-1; while j>=0 and arr[j]>key: arr[j+1]=arr[j]; j--; arr[j+1]=key.','Easy','Sorting','Any',NULL,1),
('CODING','Implement selection sort.','','Find minimum in unsorted portion, swap with first unsorted element.','For i=0 to n-2: min_idx=i; for j=i+1 to n-1: if arr[j]<arr[min_idx]: min_idx=j; swap(arr[i], arr[min_idx]).','Easy','Sorting','Any',NULL,1),
('CODING','Implement bubble sort.','','Repeatedly swap adjacent elements if out of order. After each pass, largest element bubbles to end.','For i=0 to n-1: for j=0 to n-1-i: if arr[j]>arr[j+1]: swap. Optimization: break if no swaps in a pass.','Easy','Sorting','Any',NULL,1),
('CODING','Find equilibrium index of an array (left sum == right sum).','','Precompute prefix sums. Equilibrium: leftSum == totalSum - leftSum - arr[i].','total=sum(arr). leftSum=0. For i in 0..n-1: if leftSum==total-leftSum-arr[i] return i. leftSum+=arr[i]. return -1.','Medium','Arrays','Any',NULL,1),
('CODING','Find the smallest window in a string containing all distinct characters.','','Similar to minimum window substring but target is all distinct chars in s.','Get set of distinct chars. Use sliding window to find smallest window containing all distinct chars.','Hard','Strings','Any',NULL,1),
('CODING','Print a matrix in spiral order.','','Process layer by layer: top row, right column, bottom row, left column.','Define boundaries (top,bottom,left,right). Process and shrink until boundaries cross.','Medium','Arrays','Amazon','Any',1),
('CODING','Search in a 2D matrix where each row and column is sorted.','','Start from top-right. If equal found; if greater move left; if smaller move down.','Start at (0, cols-1). If target==mat[r][c] return true. If target<mat[r][c] c--. Else r++.','Medium','Searching','Any',NULL,1),
('CODING','Find the number of ways to climb stairs (1 or 2 steps at a time).','','This is Fibonacci! f(n) = f(n-1) + f(n-2). Ways to reach step n from n-1 or n-2.','dp[1]=1, dp[2]=2. dp[n]=dp[n-1]+dp[n-2]. Same recurrence as Fibonacci.','Easy','Dynamic Programming','Any',NULL,1),
('CODING','Minimum cost path in a grid (move right or down).','','DP: cost[i][j] = grid[i][j] + min(cost[i-1][j], cost[i][j-1]).','Initialize first row and column with prefix sums. Then fill DP table.','Easy','Dynamic Programming','Any',NULL,1),
('CODING','House robber: cannot rob adjacent houses, maximize stolen money.','','dp[i] = max(dp[i-1], dp[i-2] + nums[i]).','Two variables: prev2 and prev1. For each house: curr = max(prev1, prev2+nums[i]); prev2=prev1; prev1=curr.','Easy','Dynamic Programming','Any',NULL,1),
('CODING','Regular expression matching with . and *.','','DP: dp[i][j] = s[0..i-1] matches p[0..j-1]. Handle . (any char) and * (zero or more of preceding).','dp[i][j]: if p[j-1]==s[i-1] or p[j-1]==".": dp[i][j]=dp[i-1][j-1]. If p[j-1]=="*": dp[i][j]=dp[i][j-2] (zero occurrence) or (dp[i-1][j] if prev char matches).','Hard','Dynamic Programming','Google','Any',1),
('CODING','Word break: can string s be segmented into words from dictionary?','','DP: dp[i] = true if s[0..i] can be segmented. For each i, try all j<i where dp[j] is true and s[j..i] in dict.','dp[0]=true. For i=1 to n: for j=0 to i-1: if dp[j] and s[j:i] in wordDict: dp[i]=true.','Medium','Dynamic Programming','Any',NULL,1),
('CODING','Implement a trie and use it to find all words with a given prefix.','','Trie with insert and startsWith. For prefix search: navigate to prefix end node, DFS/BFS from there collecting all words.','dfs from prefix endpoint: collect all paths from there to end nodes. Works as autocomplete.','Medium','Trie','Any',NULL,1),
('CODING','Find the strongly connected components in a directed graph (Kosaraju''s algorithm).','','1) DFS, push to stack by finish time. 2) Transpose graph. 3) DFS on transposed in stack order.','Kosaraju: DFS on original, push to stack. Transpose edges. DFS on transposed in reverse finish order gives SCCs.','Hard','Graphs','Any',NULL,1),
('CODING','Topological sort of a directed acyclic graph (DAG).','','DFS-based: post-order, push to stack. Or BFS Kahn''s: process in-degree 0 nodes.','Kahn''s: compute in-degree. Queue all 0-in-degree. Pop, add to order, decrement neighbors'' in-degree, enqueue new 0s.','Medium','Graphs','Any',NULL,1),
('CODING','Find minimum spanning tree using Kruskal''s algorithm.','','Sort edges by weight. Use Union-Find to add edges that don''t create a cycle.','Sort edges by weight. For each edge (u,v,w): if find(u)!=find(v), add to MST, union(u,v).','Hard','Graphs','Any',NULL,1),
('CODING','Implement Bellman-Ford for shortest path (handles negative weights).','','Relax all edges V-1 times. If relaxation in Vth iteration, negative cycle.','dist[src]=0, rest=INF. For V-1 iterations: for each edge (u,v,w): if dist[u]+w<dist[v]: dist[v]=dist[u]+w. Check for negative cycles.','Hard','Graphs','Any',NULL,1),
('CODING','Find number of distinct islands in a grid.','','DFS, record path (direction taken). Normalize path as signature. Count distinct signatures.','On island found, DFS collecting directions (UDLR + backtrack B). Normalize by subtracting start position. Use set of signatures.','Hard','Graphs','Google','Any',1),
('CODING','Print all paths from source to destination in a graph.','','DFS with path tracking. When destination reached, print path. Backtrack.','dfs(node, dest, path, visited): if node==dest print path. For each neighbor: if not visited, recurse.','Medium','Graphs','Any',NULL,1),
('CODING','Implement priority queue (max-heap).','','Array-based heap. Insert at end and sift up. Extract max: swap with last, remove, sift down.','parent(i)=(i-1)/2. leftChild(i)=2i+1. rightChild(i)=2i+2. siftUp: while parent > child, swap. siftDown: swap with larger child until heap property satisfied.','Medium','Heap','Any',NULL,1),
('CODING','Design a data structure for next greater element for each element in array.','','Monotonic decreasing stack. When element greater than top found, pop and assign.','Stack stores indices. For each i: while stack non-empty and arr[i]>arr[stack.top()]: result[stack.pop()]=arr[i]. Push i.','Medium','Stacks','Any',NULL,1),
('CODING','Find the maximum sum of non-adjacent elements in a circular array.','','Break circle: max of house_robber(arr[0..n-2]) and house_robber(arr[1..n-1]).','Two passes of house robber: one excluding last element, one excluding first. Take max of both.','Medium','Dynamic Programming','Any',NULL,1),
('CODING','Find the shortest path in a grid with obstacles using BFS.','','BFS from source. Mark visited. Expand to 4 neighbors if not obstacle and not visited.','BFS level by level. Each level = 1 step. When destination reached, return level.','Medium','Graphs','Any',NULL,1),
('CODING','Reconstruct itinerary from list of tickets (find Eulerian path).','','DFS with backtracking. Sort neighbors lexicographically. Hierholzer''s algorithm for Eulerian path.','Sort adjacency lists. DFS: visit neighbors in order, append to route after DFS call (reverse at end).','Hard','Graphs','Any',NULL,1),
('CODING','Validate stack sequences (given push and pop sequences, check if pop sequence is valid).','','Simulate with a stack. Push from push sequence until top matches pop, then pop.','Simulate: ptr for pop_seq. For each element in push_seq: push it. While stack non-empty and stack.top==pop_seq[ptr]: pop, ptr++. Stack empty at end = valid.','Medium','Stacks','Any',NULL,1),
('CODING','Given n, generate all valid combinations of n pairs of parentheses.','','Backtracking: track open and close count. Add open if open < n. Add close if close < open.','generate(s, open, close, n): if len(s)==2n: add. if open<n: recurse(s+"(", open+1, close). if close<open: recurse(s+")", open, close+1).','Medium','Backtracking','Any',NULL,1),
('CODING','Find the longest palindromic substring.','','Expand around each center (single char and between chars). O(n²). Or Manacher''s O(n).','For each i: expand(i,i) for odd length, expand(i,i+1) for even. Track max length palindrome.','Medium','Strings','Amazon','Any',1),
('CODING','Check if a string is a valid number (including integers and floats).','','Parse: optional sign, digits, optional decimal point and more digits, optional exponent.','State machine or careful parsing. Handle edge cases: "+", ".", "e", "1e", ".1", "1.".','Medium','Strings','Any',NULL,1),
('CODING','Roman numeral to integer conversion.','','Map values, subtract when smaller value precedes larger.','Map: I=1,V=5,X=10,L=50,C=100,D=500,M=1000. If val[s[i]]<val[s[i+1]]: subtract, else add.','Easy','Strings','Any',NULL,1),
('CODING','Integer to Roman numeral conversion.','','Greedily subtract largest possible values, appending corresponding symbols.','Values in descending order: 1000,900,500,400,... For each value: while n>=val: result+=sym; n-=val.','Medium','Strings','Any',NULL,1),
('CODING','Find all permutations of a string.','','Backtracking with character frequency to handle duplicates.','Sort string, use visited array. backtrack(current, visited): if len==n, add. For each i: if not visited[i] and (i==0 or s[i]!=s[i-1] or visited[i-1]): recurse.','Medium','Backtracking','Any',NULL,1),
('CODING','Implement pow(x, n) with negative exponents.','','If n<0: x=1/x, n=-n. Use fast exponentiation.','if n<0: return 1/pow(x,-n). if n==0: return 1. half=pow(x,n/2). if n%2==0: return half*half. else: return half*half*x.','Medium','Math','Any',NULL,1),
('CODING','Find the number of paths from top-left to bottom-right in a grid with obstacles.','','DP with obstacle check. dp[i][j]=0 if obstacle, else dp[i-1][j]+dp[i][j-1].','dp[0][0]=1 if no obstacle. First row/col = 0 once obstacle hit. Fill rest accordingly.','Medium','Dynamic Programming','Any',NULL,1),
('CODING','Maximum product subarray.','','Track both max and min (negative*negative can be max). Update both at each step.','maxSoFar=minSoFar=result=nums[0]. For i=1..n: candidates=(nums[i], maxSoFar*nums[i], minSoFar*nums[i]). maxSoFar=max, minSoFar=min, result=max(result,maxSoFar).','Medium','Dynamic Programming','Any',NULL,1),
('CODING','Longest palindromic subsequence.','','LCS of string with its reverse. Or DP: dp[i][j]=length of LPS of s[i..j].','dp[i][j]: if s[i]==s[j]: dp[i][j]=dp[i+1][j-1]+2. Else: max(dp[i+1][j], dp[i][j-1]).','Medium','Dynamic Programming','Any',NULL,1),
('CODING','Count the number of distinct subsequences of string t in string s.','','DP: dp[i][j] = count of t[0..j-1] in s[0..i-1]. If match: dp[i][j]=dp[i-1][j-1]+dp[i-1][j].','dp[i][0]=1 always (empty string). dp[0][j]=0 for j>0. Fill based on character match.','Hard','Dynamic Programming','Any',NULL,1),
('CODING','Find all nodes at distance k from a target node in binary tree.','','Annotate with parents (DFS). Then BFS from target using parent and child pointers.','Map<Node,Node> parent via DFS. BFS from target: spread to left child, right child, parent. After k steps, collect nodes.','Medium','Trees','Any',NULL,1),
('CODING','Zigzag level order traversal of binary tree.','','BFS with level tracking. Even levels: left-to-right. Odd levels: right-to-left. Use deque.','BFS with deque. At each level: if odd level, append left to right to front of deque. Else append to back.','Medium','Trees','Any',NULL,1),
('CODING','Find the right side view of a binary tree.','','BFS level by level. Last element of each level is the right side view.','Level-order BFS. At each level, rightmost visible node = last in that level.','Medium','Trees','Amazon','Any',1),
('CODING','Count number of univalue subtrees.','','Post-order DFS. Leaf nodes are univalue. Internal: both subtrees univalue and have same value.','isUnivalue(node, count): if leaf, count++, return true. leftUni=isUnivalue(left,count), rightUni=isUnivalue(right,count). If both and values match: count++, return true.','Medium','Trees','Any',NULL,1),
('CODING','Check if two trees are identical.','','Recursive: both null=true. One null=false. Values differ=false. Recurse on children.','isSame(p,q): if both null return true. if one null or p.val!=q.val return false. return isSame(p.left,q.left) && isSame(p.right,q.right).','Easy','Trees','Any',NULL,1),
('CODING','Find the kth smallest element in a BST.','','In-order traversal of BST gives sorted order. kth element in in-order is kth smallest.','Iterative in-order with counter. When counter reaches k, return current node value.','Easy','Trees','Any',NULL,1),
('CODING','Design a data structure supporting insert, delete, getRandom in O(1).','','ArrayList + HashMap. List for random access. Map for O(1) lookup. Delete: swap with last, update map.','map: value→index. list: values. getRandom: list.get(random.nextInt(list.size())). Delete: swap target with last, update map, remove last.','Hard','Design','Any',NULL,1),
('CODING','Find minimum number of meetings rooms required.','','Sort by start time. Min-heap of end times. For each meeting: if earliest end <= start, reuse room (pop); push current end.','Sort by start. minHeap of end times. For each meeting: if heap.peek()<=start: poll(). add end. Result = heap.size().','Medium','Heap','Any',NULL,1),
('CODING','Trapping rain water: given heights, find water that can be trapped.','','Two-pointer or DP. Track max from left and right. Water at i = min(maxLeft[i], maxRight[i]) - height[i].','leftMax, rightMax arrays. water+=max(0, min(leftMax[i], rightMax[i])-height[i]). Two-pointer: l=0,r=n-1. If h[l]<h[r]: process left, else right.','Hard','Arrays','Google','Any',1),
('CODING','Median of two sorted arrays in O(log(m+n)).','','Binary search on smaller array. Find partition such that left half of both < right half.','Partition smaller array at mid. Compute corresponding partition in larger. Check cross conditions (maxLeft1<=minRight2 and maxLeft2<=minRight1).','Hard','Searching','Any',NULL,1),
('CODING','Find the celebrity in a party (everyone knows celebrity but celebrity knows no one).','','Two-pointer elimination. Candidate can only be reduced, not increased.','candidate=0. For i=1..n-1: if knows(candidate,i): candidate=i. Verify candidate: knows nobody and known by all.','Medium','Arrays','Any',NULL,1),
('CODING','Implement an iterator over a 2D matrix.','','Track row and column indices. hasNext checks if within bounds. next returns current and advances.','row=0, col=0. hasNext: row<numRows. next: val=matrix[row][col]; advance col; if col==numCols: col=0; row++; return val.','Easy','Design','Any',NULL,1);

